function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
function parseCSV(text){
  const rows=[];let row=[],cur='',q=false;
  for(let i=0;i<text.length;i++){const c=text[i];
    if(q){if(c==='"'){if(text[i+1]==='"'){cur+='"';i++;}else q=false;}else cur+=c;}
    else if(c==='"')q=true;
    else if(c===','){row.push(cur);cur='';}
    else if(c==='\n'){row.push(cur);rows.push(row);row=[];cur='';}
    else if(c!=='\r')cur+=c;}
  if(cur!==''||row.length){row.push(cur);rows.push(row);}
  if(!rows.length)return[];
  const hdr=rows.shift().map(h=>h.trim().replace(/^\ufeff/,''));
  return rows.filter(r=>r.some(v=>String(v).trim()!==''))
    .map(r=>{const o={};hdr.forEach((h,i)=>o[h]=String(r[i]==null?'':r[i]).trim());return o;});
}
const num = v => { const n = parseFloat(String(v==null?'':v).replace(',','.')); return isFinite(n)?n:null; };

/*******************************************************************
 * DỰNG DANH SÁCH ĐIỂM ĐO TỪ SỔ ĐỊA BÀN  (thay cho hằng LOCATIONS hardcode)
 *
 * Tự thích ứng theo dữ liệu đã điền:
 *   - DiemDo có toạ độ  -> lấy mẫu 129 điểm (ranh giới ĐVHC cũ, bám lưu vực/bản làng)
 *   - DiemDo trống      -> rơi về 45 điểm của DiaBan (1 điểm/xã)
 *   - Cả hai trống      -> DỪNG với thông báo rõ, KHÔNG chạy tiếp với dữ liệu rác
 *
 * Nguồn danh mục: Nghị quyết 1661/NQ-UBTVQH15 (16/6/2025) — 45 ĐVHC (42 xã + 3 phường).
 *******************************************************************/
const CHUNK = 40;   // số toạ độ mỗi request Open-Meteo (multi-coordinate)
const FFPI_DEFAULT = 3.0;   // trung tính: xã chưa có FFPI dùng đúng ngưỡng gốc, không ưu ái

const dbCsv = String((($('Đọc địa bàn (DiaBan)').first()||{}).json||{}).data || '');
let ddCsv = '';
try { ddCsv = String((($('Đọc điểm đo (DiemDo)').first()||{}).json||{}).data || ''); } catch(e){}

const communes = parseCSV(dbCsv).filter(r => r.xa_id && (r.trang_thai||'active')==='active');
if (!communes.length) {
  throw new Error('Không đọc được sheet DiaBan. Kiểm tra: (1) SHEET_ID trong node "Đọc địa bàn", (2) Sheet đã Share "Anyone with the link", (3) tên sheet đúng là DiaBan.');
}

const cmap = {};
communes.forEach(c => { cmap[c.xa_id] = {
  xa_id:c.xa_id, name:c.ten_day_du || c.xa_id, loai:c.loai||'xa',
  ffpi_xa: num(c.ffpi),
  sz: (num(c.sz_lat)!=null && num(c.sz_lon)!=null) ? [num(c.sz_lat), num(c.sz_lon)] : null,
  szn: c.sz_ten || '',
  hop_thanh_tu: c.hop_thanh_tu || ''
}; });

// --- Ưu tiên DiemDo (mịn hơn cấp xã) ---
let points = [];
let mode = 'diem_do';
if (ddCsv) {
  points = parseCSV(ddCsv)
    .filter(r => r.xa_id && cmap[r.xa_id] && (r.trang_thai||'active')==='active')
    .filter(r => num(r.lat)!=null && num(r.lon)!=null)
    .map(r => ({ point_id:r.diem_id || (r.xa_id+'__'+r.ten_diem), point_name:r.ten_diem || r.diem_id,
                 xa_id:r.xa_id, lat:num(r.lat), lon:num(r.lon),
                 ffpi: num(r.ffpi) != null ? num(r.ffpi) : (cmap[r.xa_id].ffpi_xa != null ? cmap[r.xa_id].ffpi_xa : FFPI_DEFAULT) }));
}
// --- Rơi về DiaBan (1 điểm/xã) ---
if (!points.length) {
  mode = 'trung_tam_xa';
  points = communes
    .filter(r => num(r.lat)!=null && num(r.lon)!=null)
    .map(r => ({ point_id:r.xa_id, point_name:r.ten_day_du, xa_id:r.xa_id,
                 lat:num(r.lat), lon:num(r.lon),
                 ffpi: num(r.ffpi) != null ? num(r.ffpi) : FFPI_DEFAULT }));
}
if (!points.length) {
  throw new Error('Sổ địa bàn CHƯA CÓ TOẠ ĐỘ. Điền cột lat/lon ở sheet DiemDo (129 điểm) hoặc DiaBan (45 xã) rồi chạy lại. Xem sheet HuongDan để biết 3 cách lấy toạ độ.');
}

// --- Cảnh báo dữ liệu chưa hoàn thiện: KHÔNG để hệ thống im lặng chạy sai ---
const warnings = [];
const noFfpi = points.filter(p => p.ffpi === FFPI_DEFAULT).length;
if (noFfpi) warnings.push(noFfpi + '/' + points.length + ' điểm chưa có FFPI -> đang dùng ngưỡng mưa mặc định, MẤT tính cá thể hoá theo xã (yêu cầu "sub-regional"). Tính FFPI hàng loạt trên Google Earth Engine rồi dán vào sheet.');
const noSz = Object.values(cmap).filter(c => !c.sz).length;
if (noSz) warnings.push(noSz + '/' + communes.length + ' xã chưa có điểm an toàn (sz_lat/sz_lon) -> bản đồ thoát nạn sẽ trống. Đây là thông tin PHẢI lấy từ cán bộ xã, không được suy đoán.');
if (mode === 'trung_tam_xa') warnings.push('Đang lấy mẫu 1 điểm/xã. Sau sắp xếp 2025 một xã gộp tới 5-6 đơn vị cũ nên 1 điểm là THÔ so với yêu cầu "sub-regional". Điền toạ độ sheet DiemDo để lấy mẫu mịn hơn.');

// --- Chia lô toạ độ cho Open-Meteo multi-coordinate ---
const chunks = [];
for (let i=0; i<points.length; i+=CHUNK) chunks.push(points.slice(i, i+CHUNK));

const registry = { mode, n_points:points.length, n_communes:Object.keys(cmap).length,
                   points, communes:cmap, warnings, chunk_size:CHUNK, n_chunks:chunks.length };
try { $getWorkflowStaticData('global').registry = registry; } catch(e){}

return chunks.map((ch, i) => ({ json: {
  chunk_index: i, n_chunks: chunks.length,
  lat: ch.map(p=>p.lat).join(','), lon: ch.map(p=>p.lon).join(','),
  point_ids: ch.map(p=>p.point_id),
  __registry_mode: mode, __n_points: points.length
}}));

function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
