}
const num = v => { const n = parseFloat(String(v==null?'':v).replace(',','.')); return isFinite(n)?n:null; };

/*******************************************************************
 * AETHER-DB — CONSENSUS ENGINE v3  (tất định, KHÔNG dùng LLM)
 *
 * KHÁC v2: lấy mẫu tại N ĐIỂM rồi QUY VỀ XÃ theo mức rủi ro CAO NHẤT.
 *   Lý do: NQ 1661/NQ-UBTVQH15 gộp 129 ĐVHC thành 45 (có xã gộp 5-6 đơn vị).
 *   Ở địa hình núi, một xã gộp trải trên nhiều tiểu vùng khí hậu -> 1 điểm/xã là quá thô,
 *   đúng thứ đề bài phê phán. Đánh giá rủi ro MỊN HƠN cấp xã, phát tin ĐÚNG cấp xã.
 *
 * NGUỒN & ĐỘ TRỄ:
 *   Open-Meteo (ECMWF) : dự báo, real-time           -> nguồn chính
 *   GloFAS Flood       : mô hình thuỷ văn, real-time -> tín hiệu lũ sông
 *   ERA5 (bias cache)  : tái phân tích, trễ 5-7 ngày -> hiệu chỉnh CÓ ĐỘ TRỄ (flow riêng, 1 lần/ngày)
 *   OpenWeatherMap     : chỉ gọi cho xã ĐÃ cảnh báo  -> xác minh đồng thuận (tiết kiệm quota)
 *******************************************************************/
const TZ_OFFSET_MS = 7*3600*1000;
const TH = {
  RAIN_CRIT_BASE:50, RAIN_WARN_BASE:30, RAIN_ADV_BASE:15,
  SOIL_CRIT:85, FROST_WARN:4, FROST_CRIT:0,
  FOG_CRIT:50, FOG_WARN:200, FOG_ADV:500,
  Q_WARN:1.8, Q_CRIT:2.5, DRIFT_MM:20
};
const FFPI_REF = 3.0;
const RANK = { SAFE:0, ADVISORY:1, WARNING:2, CRITICAL:3 };
const sum = (a,i,j) => a.slice(Math.max(i,0), j).reduce((s,v)=>s+(v||0),0);
const thr = (base, ffpi) => +(base * (FFPI_REF / (ffpi || FFPI_REF))).toFixed(1);
const nowLocal = new Date(Date.now()+TZ_OFFSET_MS);
const todayStr = nowLocal.toISOString().slice(0,10);
const nowHourKey = nowLocal.toISOString().slice(0,13);

const sd = (()=>{ try { return $getWorkflowStaticData('global'); } catch(e){ return {}; } })();
const firstIn = $input.first().json;
const simulated = firstIn.__simulated === true;

let registry, perPoint = [];

if (simulated) {
  registry = firstIn.registry; perPoint = firstIn.points;
} else {
  registry = sd.registry;
  if (!registry) throw new Error('Chưa có registry. Node "Dựng điểm đo" phải chạy trước Consensus.');

  const fc = $('Open-Meteo Forecast').all().map(i=>i.json);
  let fl=[]; try { fl = $('Open-Meteo Flood').all().map(i=>i.json); } catch(e){}
  const bias = sd.biasByCommune || {};

  // Open-Meteo trả 1 object/toạ độ theo ĐÚNG thứ tự yêu cầu; các lô nối tiếp nhau.
  if (fc.length !== registry.points.length) {
    throw new Error('Lệch số lượng: yêu cầu ' + registry.points.length + ' điểm, nhận về ' + fc.length
      + '. Không map được điểm với dữ liệu -> DỪNG thay vì cảnh báo nhầm xã.');
  }

  perPoint = registry.points.map((P,i) => {
    const f=fc[i]||{}, h=f.hourly||{}, d=f.daily||{};
    const times=h.time||[], rain=h.precipitation||[], vis=h.visibility||[], wcH=h.weather_code||[];
    let nowIdx = times.findIndex(t => t && String(t).slice(0,13)===nowHourKey);
    if (nowIdx < 0) nowIdx = 3*24;
    let todayIdx = (d.time||[]).indexOf(todayStr);
    if (todayIdx < 0) todayIdx = 3;

    const forecast_next24 = +sum(rain, nowIdx, nowIdx+24).toFixed(1);
    const soilArr = h.soil_moisture_0_to_1cm||[];
    const soilNow = soilArr[nowIdx]!=null ? +(soilArr[nowIdx]*100).toFixed(0) : null;
    const tmins = (d.temperature_2m_min||[]).slice(todayIdx, todayIdx+2).filter(v=>v!=null);
    const t_min_next24 = tmins.length ? Math.min(...tmins) : null;

    const visWin = vis.slice(nowIdx, nowIdx+12).filter(v=>v!=null);
    let vis_min = visWin.length ? Math.min(...visWin) : null;
    if (vis_min==null && wcH.slice(nowIdx,nowIdx+12).some(c=>c===45||c===48)) vis_min = 150;

    let qRatio=null;
    const q = (((fl[i]||{}).daily)||{}).river_discharge||[];
    if (q.length>=8) {
      const past=q.slice(0,7).filter(v=>v!=null).sort((a,b)=>a-b);
      const med=past.length?past[Math.floor(past.length/2)]:null;
      const fut=q.slice(7).filter(v=>v!=null);
      if (med>0 && fut.length) qRatio=+(Math.max(...fut)/med).toFixed(2);
    }

    return { ...P, forecast_next24, soilNow, t_min_next24, vis_min, qRatio,
             bias_mm: bias[P.xa_id]!=null ? bias[P.xa_id].bias_mm : null,
             bias_per_day: bias[P.xa_id]!=null ? bias[P.xa_id].per_day : 0,
             daily:{ time:(d.time||[]).slice(todayIdx,todayIdx+7),
                     t_min:(d.temperature_2m_min||[]).slice(todayIdx,todayIdx+7),
                     t_max:(d.temperature_2m_max||[]).slice(todayIdx,todayIdx+7),
                     precip_sum:(d.precipitation_sum||[]).slice(todayIdx,todayIdx+7),
                     weather_code:(d.weather_code||[]).slice(todayIdx,todayIdx+7) } };
  });
}

// ---- Ngưỡng cứng TỪNG ĐIỂM ----
const scored = perPoint.map(p => {
  const rainCrit=thr(TH.RAIN_CRIT_BASE,p.ffpi), rainWarn=thr(TH.RAIN_WARN_BASE,p.ffpi), rainAdv=thr(TH.RAIN_ADV_BASE,p.ffpi);
  const biasCorr = Math.max(0, p.bias_per_day||0);       // chỉ cộng khi mô hình THIẾU mưa
  const effRain = (p.forecast_next24||0) + biasCorr;
  let level='SAFE', risk='none';
  if ((effRain>rainCrit && (p.soilNow||0)>TH.SOIL_CRIT) || (p.qRatio||0)>TH.Q_CRIT) {
    level='CRITICAL'; risk=(p.qRatio||0)>TH.Q_CRIT ? 'flood' : 'landslide';
  } else if (p.t_min_next24!=null && p.t_min_next24<TH.FROST_CRIT) { level='CRITICAL'; risk='frost'; }
  else if (p.vis_min!=null && p.vis_min<TH.FOG_CRIT) { level='CRITICAL'; risk='fog'; }
  else if (effRain>rainWarn || ((p.soilNow||0)>TH.SOIL_CRIT && effRain>rainAdv) || (p.qRatio||0)>TH.Q_WARN) { level='WARNING'; risk='flood'; }
  else if (p.t_min_next24!=null && p.t_min_next24<TH.FROST_WARN) { level='WARNING'; risk='frost'; }
  else if (p.vis_min!=null && p.vis_min<TH.FOG_WARN) { level='WARNING'; risk='fog'; }
  else if (p.vis_min!=null && p.vis_min<TH.FOG_ADV) { level='ADVISORY'; risk='fog'; }
  else if (effRain>rainAdv) { level='ADVISORY'; risk='rain'; }
  else if (p.t_min_next24!=null && p.t_min_next24<7) { level='ADVISORY'; risk='cold'; }
  return {...p, alert_level:level, risk_type:risk, eff_rain:+effRain.toFixed(1),
          near_threshold: effRain > rainWarn*0.8, rain_threshold_mm:rainCrit};
});

// ---- QUY VỀ XÃ: lấy điểm rủi ro CAO NHẤT làm đại diện ----
const byXa = {};
scored.forEach(p => { (byXa[p.xa_id] = byXa[p.xa_id] || []).push(p); });

const locations = [], alerts = [], diagnostics = {
  registry_mode: registry.mode, n_points: scored.length, n_communes: Object.keys(byXa).length,
  thresholds_by_location:{}, ffpi_by_location:{}, bias_by_location_mm:{}, model_drift_flag:{},
  worst_point_by_location:{}, points_by_location:{}, spread_mm_by_location:{},
  warnings: (registry.warnings||[]).slice()
};

Object.keys(byXa).forEach(xid => {
  const pts = byXa[xid].slice().sort((a,b)=>
    (RANK[b.alert_level]-RANK[a.alert_level]) || (b.eff_rain-a.eff_rain));
  const w = pts[0];                       // điểm xấu nhất = đại diện cho xã
  const C = registry.communes[xid] || {};
  const rains = pts.map(p=>p.eff_rain).filter(v=>v!=null);
  const spread = rains.length>1 ? +(Math.max(...rains)-Math.min(...rains)).toFixed(1) : 0;

  locations.push({ id:xid, name:C.name||xid, lat:w.lat, lon:w.lon, ffpi:w.ffpi,
    alert_level:w.alert_level, risk_type:w.risk_type,
    metrics:{ forecast_next24_mm:w.forecast_next24, eff_rain_mm:w.eff_rain,
      soil_moisture_pct:w.soilNow, t_min_next24_c:w.t_min_next24,
      visibility_min_m:w.vis_min, discharge_ratio:w.qRatio,
      worst_point:w.point_name, n_points:pts.length, spread_mm:spread },
    daily:w.daily||null });

  diagnostics.thresholds_by_location[xid]={rain_critical_mm:thr(TH.RAIN_CRIT_BASE,w.ffpi),
    rain_warning_mm:thr(TH.RAIN_WARN_BASE,w.ffpi), rain_advisory_mm:thr(TH.RAIN_ADV_BASE,w.ffpi)};
  diagnostics.ffpi_by_location[xid]=w.ffpi;
  diagnostics.bias_by_location_mm[xid]=w.bias_mm;
  diagnostics.model_drift_flag[xid]= w.bias_mm!=null && Math.abs(w.bias_mm)>TH.DRIFT_MM;
  diagnostics.worst_point_by_location[xid]=w.point_name;
  diagnostics.points_by_location[xid]=pts.length;
  diagnostics.spread_mm_by_location[xid]=spread;

  if (['WARNING','CRITICAL'].includes(w.alert_level)) {
    alerts.push({ id:xid, name:C.name||xid, sz:C.sz, szn:C.szn, ffpi:w.ffpi,
      alert_level:w.alert_level, risk_type:w.risk_type,
      metrics:{ forecast_next24_mm:w.forecast_next24, eff_rain_mm:w.eff_rain,
        soil_moisture_pct:w.soilNow, t_min_next24_c:w.t_min_next24, visibility_min_m:w.vis_min,
        discharge_ratio:w.qRatio, bias_mm:w.bias_mm, rain_threshold_mm:w.rain_threshold_mm,
        worst_point:w.point_name, n_points_in_commune:pts.length, spread_mm:spread },
      lat:w.lat, lon:w.lon });
  }
});

// ---- Cảnh báo vận hành: không tầng nào được chết âm thầm ----
if (!simulated) {
  if (!Object.keys(sd.biasByCommune||{}).length)
    diagnostics.warnings.push('Chưa có bias ERA5 -> tầng hiệu chuẩn TẮT. Luồng "Bias ERA5 hằng ngày" phải chạy ít nhất 1 lần (Schedule 02:00, hoặc Execute thủ công).');
  const noSz = alerts.filter(a=>!a.sz).length;
  if (noSz) diagnostics.warnings.push(noSz + ' xã đang cảnh báo NHƯNG chưa có điểm an toàn trong sổ địa bàn -> tin nhắn sẽ không có nơi để chỉ dân chạy tới.');
}

const payload = { schema_version:'3.0', generated_at:new Date().toISOString(), simulated,
  confidence: simulated ? 'SIMULATED' : (Object.keys(sd.biasByCommune||{}).length ? 'HIGH' : 'MEDIUM'),
  source_agreement: null,           // do node "Xác minh OpenWeatherMap" điền sau
  locations, diagnostics };
try { sd.latestForecast = payload; } catch(e){}

return [{ json: { ...payload, alerts } }];

// Chỉ gọi OpenWeatherMap cho các xã ĐÃ vượt ngưỡng -> ngày thường tốn 0 call.
// Free tier OWM chỉ 1.000 call/ngày; gọi đại trà 45 xã × 24 vòng = 1.080 -> vỡ quota.
const d = $input.first().json;
if (!d.alerts || !d.alerts.length) return [];
return d.alerts.map(a => ({ json:{ xa_id:a.id, lat:a.lat, lon:a.lon } }));

// Đối chiếu OpenWeatherMap với Open-Meteo -> đồng thuận hay không.
// NGUYÊN TẮC AN TOÀN TRƯỚC: hai nguồn mâu thuẫn thì VẪN cảnh báo, chỉ hạ confidence
// và gắn cờ để cán bộ xã xác minh. Không bao giờ vì mâu thuẫn mà im lặng.
const DISAGREE_MM = 25;
const base = $('Consensus Engine').first().json;
const pts = $('Xã cần xác minh').all().map(i=>i.json);
const ow  = $input.all().map(i=>i.json);

const alerts = (base.alerts||[]).map(a => ({...a, metrics:{...a.metrics}}));
const cut = Date.now()/1000 + 86400;
let checked=0, disagree=0;

pts.forEach((P,i) => {
  const list = (ow[i]||{}).list || [];
  if (!list.length) return;
  const owm = +list.filter(x=>x.dt<=cut).reduce((s,x)=>s+(((x.rain||{})['3h'])||0),0).toFixed(1);
  const a = alerts.find(x=>x.id===P.xa_id); if (!a) return;
  const gap = +Math.abs((a.metrics.forecast_next24_mm||0) - owm).toFixed(1);
  a.metrics.owm_next24_mm = owm;
  a.metrics.source_disagreement_mm = gap;
  a.metrics.eff_rain_mm = Math.max(a.metrics.eff_rain_mm||0, owm);   // MAX -> không bỏ sót
  a.metrics.needs_field_check = gap > DISAGREE_MM;
  checked++; if (gap > DISAGREE_MM) disagree++;
});

const agreement = checked>0 && disagree===0;
const payload = {...base, alerts, source_agreement:agreement,
  confidence: (agreement && base.confidence==='HIGH') ? 'HIGH' : 'MEDIUM'};
payload.diagnostics = {...base.diagnostics};
payload.diagnostics.owm_checked = checked;
payload.diagnostics.owm_disagree = disagree;
if (!checked) payload.diagnostics.warnings = (payload.diagnostics.warnings||[])
  .concat('Không xác minh được bằng OpenWeatherMap (thiếu key hoặc key chưa kích hoạt — key mới cần tới ~2 giờ). Cảnh báo VẪN phát, confidence hạ xuống MEDIUM.');
try { $getWorkflowStaticData('global').latestForecast = { ...payload, alerts: undefined }; } catch(e){}
return [{ json: payload }];

// Mini knowledge-base lịch sử thiên tai Điện Biên — bản MVP thay Qdrant.
// Khi có dữ liệu thật từ Ban Chỉ huy PCTT & TKCN: thay HISTORY bằng Qdrant retriever.
const HISTORY = [
