function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
function parseCSV(text){
  const rows=[];let row=[],cur='',q=false;
  for(let i=0;i<text.length;i++){const c=text[i];
    if(q){if(c==='"'){if(text[i+1]==='"'){cur+='"';i++;}else q=false;}else cur+=c;}
    else if(c==='"')q=true;
    else if(c===','){row.push(cur);cur='';}
    else if(c==='\n'){row.push(cur);rows.push(row);row=[];cur='';}
    else if(c!=='\r')cur+=c;}
  if(cur!==''||row.length){row.push(cur);rows.push(row);}
  if(!rows.length)return[];
  const hdr=rows.shift().map(h=>h.trim().replace(/^\ufeff/,''));
  return rows.filter(r=>r.some(v=>String(v).trim()!==''))
    .map(r=>{const o={};hdr.forEach((h,i)=>o[h]=String(r[i]==null?'':r[i]).trim());return o;});
}

