  if(cur!==''||row.length){row.push(cur);rows.push(row);}
  if(!rows.length)return[];
  const hdr=rows.shift().map(h=>h.trim().replace(/^\ufeff/,''));
  return rows.filter(r=>r.some(v=>String(v).trim()!==''))
    .map(r=>{const o={};hdr.forEach((h,i)=>o[h]=String(r[i]==null?'':r[i]).trim());return o;});
}
const num = v => { const n = parseFloat(String(v==null?'':v).replace(',','.')); return isFinite(n)?n:null; };

// Bias tính ở CẤP XÃ (45 request/ngày), không phải cấp điểm (129).
// Lý do: bias là đặc tính của mô hình ở quy mô ~10km; ERA5 25km không phân giải mịn hơn được.
// Các điểm trong cùng xã dùng chung bias của xã đó.
const csv = String((($input.first()||{}).json||{}).data || '');
const rows = parseCSV(csv).filter(r => r.xa_id && (r.trang_thai||'active')==='active')
  .filter(r => num(r.lat)!=null && num(r.lon)!=null);
if (!rows.length) return [{ json:{ __skip:true, note:'Sổ địa bàn chưa có toạ độ -> bỏ qua vòng hiệu chuẩn.' } }];
return rows.map(r => ({ json:{ xa_id:r.xa_id, name:r.ten_day_du, lat:num(r.lat), lon:num(r.lon) } }));

// Tính bias từng xã = ERA5 − Open-Meteo trên CÙNG cửa sổ ngày, lưu cache cho Consensus dùng.
// ⚠️ ERA5-Land (9km) trễ THẬT 1-2 tuần -> hay trả toàn null mà node vẫn 200 OK.
//    Vì vậy xin cả era5_land lẫn era5 (25km, trễ 5 ngày) rồi quét key, ưu tiên Land.
const pts = $('Điểm hiệu chuẩn (cấp xã)').all().map(i=>i.json);
const era = $('ERA5 archive (bias)').all().map(i=>i.json);
const omh = $('Open-Meteo lịch sử (bias)').all().map(i=>i.json);

const out = {}; let okLand=0, okEra5=0, fail=0;
pts.forEach((P,i) => {
  const ed = ((era[i]||{}).daily)||{};
  const od = ((omh[i]||{}).daily)||{};
  if (!(ed.time||[]).length || !(od.time||[]).length) { fail++; return; }

  const keys = Object.keys(ed).filter(k => k.indexOf('precipitation_sum')===0);
  const prefer = ['precipitation_sum_era5_land','precipitation_sum','precipitation_sum_era5'];
  const ordered = prefer.filter(k=>keys.indexOf(k)>=0).concat(keys.filter(k=>prefer.indexOf(k)<0));
  const omMap = {}; (od.time||[]).forEach((t,k)=>{ omMap[t]=(od.precipitation_sum||[])[k]; });

  for (const key of ordered) {
    const arr = ed[key]||[];
    let es=0, os=0, n=0;
    ed.time.forEach((t,k)=>{ const ev=arr[k];
      if (ev!=null && omMap[t]!=null) { es+=ev; os+=omMap[t]; n++; } });
    if (n>0) {
      const src = key.replace('precipitation_sum','').replace(/^_/,'') || 'era5_land';
      out[P.xa_id] = { bias_mm:+(es-os).toFixed(1), per_day:+((es-os)/n).toFixed(2),
                       n_days:n, source:src, updated_at:new Date().toISOString() };
      if (src==='era5_land') okLand++; else okEra5++;
      return;
    }
  }
  fail++;
});

try { $getWorkflowStaticData('global').biasByCommune = out; } catch(e){}
return [{ json:{ n_communes:pts.length, calibrated:Object.keys(out).length,
  from_era5_land:okLand, from_era5:okEra5, failed:fail,
  note: fail ? (fail + ' xã không hiệu chuẩn được -> Consensus dùng dự báo thô cho các xã đó.') : 'Hiệu chuẩn đủ toàn tỉnh.' } }];

// Chuẩn hoá số điện thoại VN sang E.164 (+84) cho SMS gateway quốc tế
function toE164(sdt){
  var s = String(sdt==null?'':sdt).replace(/[^0-9+]/g,'');
  if(s.indexOf('+')===0) return s;
  if(s.indexOf('84')===0 && s.length>=11) return '+'+s;
  if(s.indexOf('0')===0) return '+84'+s.slice(1);
  if(s.length===9) return '+84'+s;
  return s;
}

function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
function parseCSV(text){
  const rows=[];let row=[],cur='',q=false;
  for(let i=0;i<text.length;i++){const c=text[i];
    if(q){if(c==='"'){if(text[i+1]==='"'){cur+='"';i++;}else q=false;}else cur+=c;}
    else if(c==='"')q=true;
    else if(c===','){row.push(cur);cur='';}
    else if(c==='\n'){row.push(cur);rows.push(row);row=[];cur='';}
    else if(c!=='\r')cur+=c;}
  if(cur!==''||row.length){row.push(cur);rows.push(row);}
  if(!rows.length)return[];
  const hdr=rows.shift().map(h=>h.trim().replace(/^\ufeff/,''));
  return rows.filter(r=>r.some(v=>String(v).trim()!==''))
    .map(r=>{const o={};hdr.forEach((h,i)=>o[h]=String(r[i]==null?'':r[i]).trim());return o;});
}

// BẢN TIN SÁNG (5h) — dự báo + khuyến nông, gom theo NHÓM (xã × sinh kế) để tiết kiệm token.
// 3 xã × tối đa 5 nhóm sinh kế = tối đa 15 lời gọi LLM/ngày thay vì 1 lời gọi/người.
const MODEL = 'DeepSeek-V4-Flash';  // <-- THAY: model ID từ marketplace.fptcloud.com

const csv = String(($input.first().json||{}).data || '');
const people = parseCSV(csv).filter(p=>(p.trang_thai||'active')==='active' && p.so_dien_thoai);
let fc = null;
try { fc = $getWorkflowStaticData('global').latestForecast || null; } catch(e){}
if (!fc || !fc.locations) {
  return [{ json:{ __skip:true, note:'Chưa có cache dự báo — pipeline chính phải chạy ít nhất 1 lần trước.' } }];
}

const WMO = {0:'trời quang',1:'ít mây',2:'có mây',3:'nhiều mây',45:'sương mù',48:'sương mù đóng băng',
  51:'mưa phùn nhẹ',53:'mưa phùn',55:'mưa phùn nặng hạt',61:'mưa nhỏ',63:'mưa',65:'mưa to',
  71:'tuyết nhẹ',73:'tuyết',80:'mưa rào nhẹ',81:'mưa rào',82:'mưa rào rất to',95:'dông',96:'dông kèm mưa đá'};
const SINH_KE_VN = { lua_nuoc:'trồng lúa nước', ngo_nuong:'trồng ngô trên nương',
  chan_nuoi:'chăn nuôi trâu bò', thao_qua:'trồng thảo quả trong rừng', khac:'sinh kế khác' };

const groups = [];
for (const L of fc.locations) {
  const d = L.daily || {};
  const today = {
    ngay: (d.time||[])[0],
    nhiet_do_thap: (d.t_min||[])[0], nhiet_do_cao: (d.t_max||[])[0],
    luong_mua_mm: (d.precip_sum||[])[0],
    thoi_tiet: WMO[(d.weather_code||[])[0]] || 'thay đổi',
    tam_nhin_m: (L.metrics||{}).visibility_min_m,
    muc_canh_bao: L.alert_level, loai_rui_ro: L.risk_type
  };
  const dp3 = (d.time||[]).slice(0,3).map((t,i)=>({ngay:t,
    thap:(d.t_min||[])[i], cao:(d.t_max||[])[i], mua_mm:(d.precip_sum||[])[i],
    troi:WMO[(d.weather_code||[])[i]]||'thay đổi'}));

  // Số liệu thật để node SMS chèn thẳng (không để AI bịa)
  const wf_facts = {
    ngay: today.ngay, thap: today.nhiet_do_thap, cao: today.nhiet_do_cao,
    mua_mm: today.luong_mua_mm, troi: today.thoi_tiet,
    mua_3ngay: dp3.map(x=>x.mua_mm),
    canh_bao: L.alert_level, rui_ro: L.risk_type
  };
  const sks = [...new Set(people.filter(p=>p.xa_id===L.id).map(p=>p.sinh_ke||'khac'))];
  for (const sk of sks) {
    const rcps = people.filter(p=>p.xa_id===L.id && (p.sinh_ke||'khac')===sk);
    if (!rcps.length) continue;

    const system = [
      '# ROLE',
      'Bạn là cán bộ khuyến nông kiêm truyền thông thời tiết cho bà con dân tộc thiểu số vùng cao Điện Biên.',
      '# TASK',
      'Viết bản tin thời tiết buổi sáng gửi qua SMS cho nhóm bà con làm nghề: ' + (SINH_KE_VN[sk]||sk) + '.',
      'Bản tin phải trả lời đúng 2 câu hỏi của bà con: "Hôm nay trời thế nào?" và "Vậy tôi nên làm gì với công việc của tôi?".',
      '# RULES',
      '1. "thoi_tiet": 1 câu, tối đa 12 từ, nói trời hôm nay + nhiệt độ. Không dùng mm, %, hPa.',
      '2. "khuyen_nghi": 1 câu, tối đa 14 từ, việc CẦN LÀM hoặc CẦN TRÁNH hôm nay, gắn thẳng với nghề ' + (SINH_KE_VN[sk]||sk) + '.',
      '   Phải cụ thể theo mùa vụ và tập quán vùng cao (đi nương, thả trâu bò, phơi thóc, vào rừng...).',
      '   Nếu thời tiết bình thường, vẫn đưa lời khuyên hữu ích (VD: tranh thủ phơi thóc, tra ngô).',
      '3. Ngôn ngữ đời thường, như người cùng bản nói với nhau. Không thuật ngữ.',
      '4. Trả về DUY NHẤT JSON: {"thoi_tiet":"...","khuyen_nghi":"..."} — không markdown.'
    ].join('\n');
    const user = JSON.stringify({ dia_diem:L.name, hom_nay:today, ba_ngay_toi:dp3, nghe_cua_ba_con:SINH_KE_VN[sk]||sk });

    groups.push({ json: {
      xa_id:L.id, xa_name:L.name, weather_facts:wf_facts, sinh_ke:sk,
      recipients: rcps.map(p=>({to:toE164(p.so_dien_thoai), ho_ten:p.ho_ten, ban:p.ban, vai_tro:p.vai_tro, ngon_ngu:p.ngon_ngu})),
      alert_level: L.alert_level,
      request_body:{ model:MODEL, messages:[{role:'system',content:system},{role:'user',content:user}],
                     temperature:0.5, max_tokens:250 }
    }});
  }
}
return groups;

let data=null;
try { data = $getWorkflowStaticData('global').latestForecast || null; } catch(e){}
if (!data) data = { status:'warming_up',
  message:'Chưa có dữ liệu. Workflow phải ở trạng thái Active và pipeline đã chạy ít nhất 1 chu kỳ — hoặc gọi POST /webhook/aether-simulate để kích hoạt Demo Mode.' };
return [{ json:data }];

