   +'<ellipse cx="300" cy="66" rx="95" ry="50"/><ellipse cx="300" cy="66" rx="70" ry="36"/>'
   +'<ellipse cx="300" cy="66" rx="45" ry="23"/><ellipse cx="300" cy="66" rx="22" ry="11"/>'
   +'<ellipse cx="66" cy="182" rx="78" ry="40"/></g>'
   +'<path d="M8 192 Q120 202 200 164 T392 144" stroke="rgba(255,255,255,.3)" stroke-width="9" fill="none"/>'
   +'<path d="M92 170 Q148 144 208 126 T288 78" stroke="#fff" stroke-width="4" fill="none" stroke-dasharray="10 8"/>'
   +'<circle cx="92" cy="170" r="15" fill="rgba(255,255,255,.28)"><animate attributeName="r" values="11;21;11" dur="1.8s" repeatCount="indefinite"/></circle>'
   +'<circle cx="92" cy="170" r="7" fill="#fff"/>'
   +'<path d="M288 78 l0 -28 21 8 -21 8" fill="#4CAF50"/><circle cx="288" cy="78" r="8" fill="#4CAF50"/>'
