   +'<div class="badge">'+svg('plane')+' Xem được khi không có mạng</div>'
   +'<div class="ts">Phát lúc '+new Date((p.ts||0)*1000).toLocaleTimeString('vi-VN',{hour:'2-digit',minute:'2-digit'})
