function raySet(cx,cy,angles,r1,r2,w){var s='';angles.forEach(function(a){var rad=a*Math.PI/180;
  s+='<line x1="'+(cx+r1*Math.cos(rad)).toFixed(1)+'" y1="'+(cy+r1*Math.sin(rad)).toFixed(1)
   +'" x2="'+(cx+r2*Math.cos(rad)).toFixed(1)+'" y2="'+(cy+r2*Math.sin(rad)).toFixed(1)
   +'" stroke="#F59E0B" stroke-width="'+w+'" stroke-linecap="round"/>';});return s;}
function drops(pts,color,w,len){var s='';pts.forEach(function(p){
  s+='<line x1="'+p[0]+'" y1="'+p[1]+'" x2="'+(p[0]-(len>10?5:4))+'" y2="'+(p[1]+len)+'" stroke="'+color+'" stroke-width="'+w+'" stroke-linecap="round"/>';});return s;}
