function renderForecast(data,pick){
  if(!data.locations||!data.locations.length){app.innerHTML='<div class="load">'+esc(data.message||'Chua co du lieu.')+'</div>';return;}
  var idx=0; if(pick){data.locations.forEach(function(l,n){if(l.id===pick)idx=n;});}
  var view='day'; // 'day' = 7 ngày | 'hour' = 24 giờ

  function hourLabel(t){ var d=new Date(t); var h=d.getHours(); return (h<10?'0':'')+h+'h'; }
  function partOfDay(t){ var h=new Date(t).getHours();
