  function draw(){
    var L=data.locations[idx], d=L.daily||{}, hr=L.hourly||{}, lv=L.alert_level||'SAFE';
    var t0=(d.t_max||[])[0], wc=(d.weather_code||[])[0], solid=LVSOLID[lv];
    var when=data.generated_at?new Date(data.generated_at).toLocaleTimeString('vi-VN',{hour:'2-digit',minute:'2-digit'}):'--:--';
    var m=(L.metrics||{}), cov=(data.coverage||{});

    var h='<div class="fcw">';
    // ===== Thanh chọn xã (chuyển qua lại) =====
    h+='<div class="xbar"><div class="xrow">';
    data.locations.forEach(function(l,k){
      var lc=LVSOLID[l.alert_level||'SAFE'];
      h+='<button class="xchip'+(k===idx?' on':'')+'" data-k="'+k+'">'
        +'<span class="xdot" style="background:'+lc+'"></span>'
        +esc(String(l.name).replace(/^(Xã|Phường) /,'').replace(/\s*\(.*\)$/,''))+'</button>';
    });
    h+='</div></div>';

    // ===== HERO (Apple Weather style) =====
    h+='<div class="hero3" style="background:linear-gradient(160deg,'+solid+' 0%,'+shade(solid)+' 100%)">'
      +'<div class="h3top">'+esc(String(L.name).replace(/^(Xã|Phường) /,''))+'</div>'
      +'<div class="h3date">'+fullDate((d.time||[])[0])+'</div>'
      +'<div class="h3ico">'+weatherColorSVG(wc,120)+'</div>'
      +'<div class="h3temp">'+(t0!=null?Math.round(t0):'--')+'<span>°</span></div>'
      +'<div class="h3stat">'+esc(HEROLINE[lv])+'</div>'
      +'<div class="h3sub">'+esc(wmoText(wc))
        +(m.forecast_next24_mm!=null?' · mưa '+Math.round(m.forecast_next24_mm)+'mm':'')+'</div>'
      +'</div>';

    // ===== Thang 4 cấp =====
    h+='<div class="scale2">';
    ['SAFE','ADVISORY','WARNING','CRITICAL'].forEach(function(x){
      var on=x===lv;
      h+='<div class="lv2'+(on?' on':'')+'" style="'+(on?'background:'+LVSOLID[x]+';box-shadow:0 4px 16px '+LVSOLID[x]+'66;border-color:'+LVSOLID[x]:'background:'+LVCHIP[x])+'">'
        +alertShapeSVG(x,on?24:20,on?'#fff':LVSOLID[x])
        +'<span style="color:'+(on?'#fff':LVCHIPTX[x])+'">'+({SAFE:'AN TOÀN',ADVISORY:'CHÚ Ý',WARNING:'CẢNH BÁO',CRITICAL:'NGUY HIỂM'}[x])+'</span></div>';
    });
    h+='</div>';

    // ===== Tab chuyển Ngày / Giờ =====
    var hasHour = hr.time && hr.time.length;
    h+='<div class="tabs"><button class="tab'+(view==='day'?' on':'')+'" data-v="day">7 NGÀY TỚI</button>';
    if(hasHour) h+='<button class="tab'+(view==='hour'?' on':'')+'" data-v="hour">24 GIỜ TỚI</button>';
    h+='</div>';

    if(view==='hour' && hasHour){
      // ===== 24 giờ =====
      h+='<div class="hourwrap"><div class="hourrow">';
      var th=((data.diagnostics||{}).thresholds_by_location||{})[L.id]||{};
      (hr.time||[]).slice(0,24).forEach(function(t,k){
        var pc=(hr.precip||[])[k], wcd=(hr.wcode||[])[k];
        var big=(k===0);
        h+='<div class="hcell'+(big?' now':'')+'">'
          +'<span class="hlb">'+(big?'Bây giờ':hourLabel(t))+'</span>'
          +'<span class="hpart">'+partOfDay(t)+'</span>'
          +weatherColorSVG(wcd,34)
          +'<span class="hpc">'+(pc!=null?(Math.round(pc*10)/10+'mm'):'—')+'</span></div>';
      });
      h+='</div></div>';
    } else {
      // ===== 7 ngày =====
      h+='<div class="days2wrap"><div class="days2">';
      var th=((data.diagnostics||{}).thresholds_by_location||{})[L.id]||{};
      (d.time||[]).slice(0,7).forEach(function(dt,k){
        var mx=(d.t_max||[])[k],mn=(d.t_min||[])[k],c=(d.weather_code||[])[k],ps=(d.precip_sum||[])[k]||0;
        var r='SAFE';
        if(ps>(th.rain_critical_mm||50))r='CRITICAL';else if(ps>(th.rain_warning_mm||30))r='WARNING';
        else if(ps>(th.rain_advisory_mm||15))r='ADVISORY';
        if(mn!=null&&mn<4)r=(mn<0?'CRITICAL':'WARNING');
        var today=k===0;
        h+='<div class="day2" style="'+(today?'background:'+LVCHIP[r]+';border-color:'+LVSOLID[r]+'55':'background:#fff;border-color:#eef1f4')+'">'
          +'<span class="d2n">'+(today?'Hôm nay':['CN','T2','T3','T4','T5','T6','T7'][new Date(dt).getDay()])+'</span>'
          +'<span class="d2d">'+dt.slice(8,10)+'/'+dt.slice(5,7)+'</span>'
          +weatherColorSVG(c,38)
          +(ps>0?'<span class="d2p">'+Math.round(ps)+'mm</span>':'<span class="d2p" style="opacity:.4">—</span>')
          +'<span class="d2t">'+(mx!=null?Math.round(mx):'--')+'°<small>'+(mn!=null?Math.round(mn):'--')+'°</small></span>'
          +'<span class="d2bar" style="background:'+LVSOLID[r]+'"></span></div>';
      });
      h+='</div></div>';
    }

    // ===== Footer =====
    h+='<div class="foot2"><div class="frow">'+svg('plane','')+' Cập nhật '+when
      +(m.n_points>1?' · '+m.n_points+' điểm đo':'')+'</div>'
      +'<div class="fchip"><svg width="15" height="15" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" fill="#16a34a"/><polyline points="7,12 10.5,15.5 17,9" stroke="#fff" stroke-width="2.5" fill="none" stroke-linecap="round" stroke-linejoin="round"/></svg>'
      +(cov.communes?cov.communes+' xã toàn tỉnh':'Dữ liệu thật')+'</div></div>';

    h+='</div>';
    app.innerHTML=h;

    document.querySelectorAll('.xchip').forEach(function(b){b.onclick=function(){idx=+b.dataset.k;draw();
      var el=document.querySelector('.xchip.on'); if(el&&el.scrollIntoView)el.scrollIntoView({inline:'center',block:'nearest'});};});
    document.querySelectorAll('.tab').forEach(function(b){b.onclick=function(){view=b.dataset.v;draw();};});
  }
  draw();
}
// làm tối màu cho gradient hero
function shade(hex){
  var c=hex.replace('#',''); var r=parseInt(c.slice(0,2),16),g=parseInt(c.slice(2,4),16),b=parseInt(c.slice(4,6),16);
  r=Math.round(r*0.72);g=Math.round(g*0.72);b=Math.round(b*0.72);
  return '#'+[r,g,b].map(function(x){return ('0'+x.toString(16)).slice(-2);}).join('');
}
