const html = "/* Aether-DB Service Worker — phục vụ webview KHI MẤT MẠNG.
   Phải được trả về với header:  Content-Type: application/javascript
                                 Service-Worker-Allowed: /webhook/
   Scope = /webhook/ vì script nằm ở /webhook/aether-sw. */
var CACHE = 'aether-db-v3';
var SHELL = './aether-view';

self.addEventListener('install', function(e){
  self.skipWaiting();
  e.waitUntil(caches.open(CACHE).then(function(c){
    // Cache vỏ trang. Payload cảnh báo nằm TRONG url (?data=) nên không cần mạng để render.
    return c.add(new Request(SHELL, { cache: 'reload' })).catch(function(){});
  }));
});

self.addEventListener('activate', function(e){
  e.waitUntil(caches.keys().then(function(ks){
    return Promise.all(ks.filter(function(k){ return k!==CACHE; }).map(function(k){ return caches.delete(k); }));
  }).then(function(){ return self.clients.claim(); }));
});

self.addEventListener('fetch', function(e){
  var url = new URL(e.request.url);
  if (e.request.method !== 'GET') return;

  // 1. Trang cảnh báo: LUÔN trả vỏ đã cache, bỏ qua query string (?data=... luôn khác nhau)
  if (url.pathname.indexOf('/aether-view') >= 0) {
    e.respondWith(
      caches.match(SHELL, { ignoreSearch: true }).then(function(hit){
        if (hit) {
          // Có mạng thì âm thầm làm mới vỏ cho lần sau
          fetch(e.request).then(function(r){
            if (r && r.ok) caches.open(CACHE).then(function(c){ c.put(SHELL, r.clone()); });
          }).catch(function(){});
          return hit;
        }
        return fetch(e.request);
      })
    );
    return;
  }

  // 2. API dự báo: mạng trước, hết mạng thì lấy bản lưu gần nhất (dữ liệu cũ còn hơn màn hình trắng)
  if (url.pathname.indexOf('/aether-forecast') >= 0) {
    e.respondWith(
      fetch(e.request).then(function(r){
        if (r && r.ok) { var cl = r.clone(); caches.open(CACHE).then(function(c){ c.put(e.request, cl); }); }
        return r;
      }).catch(function(){ return caches.match(e.request); })
    );
    return;
  }

  // 3. Tài nguyên khác (mp3 tiếng Mông/Thái, icon): cache trước
  e.respondWith(caches.match(e.request).then(function(hit){
    return hit || fetch(e.request).then(function(r){
      if (r && r.ok && r.type === 'basic') { var cl = r.clone(); caches.open(CACHE).then(function(c){ c.put(e.request, cl); }); }
      return r;
    }).catch(function(){ return hit; });
  }));
});
";
return [{ json: { html } }];

// Trạm loa gọi kèm ?x=<xa_id>.
// KHÔNG dựa vào static data riêng (không persist qua execution) — TỰ SINH bản tin
// từ latestForecast (nguồn mà /aether-forecast đã đọc được ổn định).
const xa = ($json.query && $json.query.x) ? String($json.query.x) : null;
const sd = (function(){ try { return $getWorkflowStaticData('global'); } catch(e){ return {}; } })();

// 1) Ưu tiên CẢNH BÁO khẩn nếu có
const alert = sd.latestLoa || null;
if (alert && alert.ts && (!xa || alert.loc === xa)) {
  const o = Object.assign({}, alert); o.kind='canh_bao';
  return [{ json: o }];
}

// 2) Bản tin sáng: tự dựng từ latestForecast
const fc = sd.latestForecast || null;
if (!fc || !fc.locations || !xa) {
  return [{ json: { ts:0, idle:true, note:'Chua co du lieu du bao. Chay pipeline chinh truoc.' } }];
}
const L = fc.locations.filter(function(x){ return x.id===xa; })[0];
if (!L) return [{ json: { ts:0, idle:true, note:'Khong tim thay xa '+xa } }];

const d = L.daily || {};
const WMO = {0:'trời quang',1:'ít mây',2:'có mây',3:'nhiều mây',45:'sương mù',48:'sương mù',
  51:'mưa phùn',53:'mưa phùn',55:'mưa phùn nặng hạt',61:'mưa nhỏ',63:'mưa',65:'mưa to',
  71:'có tuyết',73:'có tuyết',80:'mưa rào',81:'mưa rào',82:'mưa rào to',95:'dông',96:'dông, mưa đá'};
const troi = WMO[(d.weather_code||[])[0]] || 'thay đổi';
const thap = (d.t_min||[])[0], cao = (d.t_max||[])[0];
const mm = (d.precip_sum||[])[0];
const sn = String(L.name||xa).replace(/^(Xã|Phường) /,'');

var mua = '';
if (mm!=null){ if(mm<1)mua='hầu như không mưa'; else if(mm<16)mua='có mưa nhỏ';
  else if(mm<30)mua='có mưa'; else if(mm<50)mua='có mưa to'; else mua='có mưa rất to, đề phòng lũ'; }
var nhiet = (thap!=null&&cao!=null) ? ('nhiệt độ từ '+Math.round(thap)+' đến '+Math.round(cao)+' độ') : '';

var cb = '';
if (L.alert_level && L.alert_level!=='SAFE'){
  var ten = {flood:'lũ quét',landslide:'sạt lở đất',frost:'rét hại',fog:'sương mù dày'}[L.risk_type]||'thời tiết nguy hiểm';
  cb = ' Đặc biệt chú ý, hôm nay có nguy cơ '+ten+', bà con hết sức cẩn thận.';
}

const script = 'Bà con '+sn+' chú ý. Bản tin thời tiết sáng nay. Hôm nay trời '+troi+', '
  + [mua,nhiet].filter(Boolean).join(', ') + '.' + cb
  + ' Bà con nhớ xem thời tiết trước khi đi làm. Xin cảm ơn.';

return [{ json: {
  ts: Math.floor(new Date(fc.generated_at||Date.now()).getTime()/1000),
  loc: xa, name: L.name, lv: L.alert_level||'SAFE',
  title: 'Bản tin sáng '+sn, loa_script: script, audio_url:'', kind:'ban_tin_sang'
} }];

