<script>
var armed=false,lastTs=0,ac=null;
var XA=(new URLSearchParams(location.search)).get('x')||'';
function now(){return new Date().toLocaleTimeString('vi-VN',{hour12:false});}
function log(m,a){var l=document.getElementById('log');var d=document.createElement('div');
  if(a)d.className='a';d.textContent='['+now()+'] '+m;l.insertBefore(d,l.firstChild);
  while(l.children.length>60)l.removeChild(l.lastChild);}
setInterval(function(){document.getElementById('clk').textContent=now();},1000);

function chime(){ if(!ac)return;
  [880,660].forEach(function(f,i){ var o=ac.createOscillator(),g=ac.createGain();
    o.connect(g);g.connect(ac.destination);o.frequency.value=f;o.type='sine';
    var t=ac.currentTime+i*0.42; g.gain.setValueAtTime(0.0001,t);
    g.gain.exponentialRampToValueAtTime(0.28,t+0.04); g.gain.exponentialRampToValueAtTime(0.0001,t+0.4);
    o.start(t);o.stop(t+0.42); }); }

function pickVoice(){ var vs=window.speechSynthesis?speechSynthesis.getVoices():[];
  var v=vs.filter(function(x){return /vi[-_]VN|Vietnamese/i.test(x.lang+' '+x.name);})[0];
  document.getElementById('voice').textContent = v
    ? 'Giọng tiếng Việt: '+v.name+' ✓  (tiếng Mông/Thái dùng file mp3 thu sẵn — điền audio_url trong n8n)'
    : '⚠ Không tìm thấy giọng tiếng Việt trên máy này. Dùng Chrome/Edge trên Windows hoặc Android, hoặc điền audio_url mp3 thu sẵn trong n8n.';
  return v; }
if(window.speechSynthesis){ speechSynthesis.onvoiceschanged=pickVoice; setTimeout(pickVoice,400); }

function say(text,times,audioUrl){
  if(!armed)return;
  if(audioUrl){ var n=0; var a=new Audio(audioUrl);
    a.onended=function(){ n++; if(n<times){ a.currentTime=0; a.play(); } };
    a.onerror=function(){ log('✗ Lỗi tải mp3, chuyển sang giọng máy tiếng Việt'); say(text,times,''); };
    chime(); setTimeout(function(){a.play();},900); return; }
  if(!window.speechSynthesis){ log('✗ Thiết bị không hỗ trợ đọc tự động'); return; }
  speechSynthesis.cancel(); chime();
  setTimeout(function(){
    for(var i=0;i<times;i++){ var u=new SpeechSynthesisUtterance(text);
      u.lang='vi-VN'; u.rate=0.8; u.volume=1; var v=pickVoice(); if(v)u.voice=v;
      if(i===times-1)u.onend=function(){ log('✓ Phát xong '+times+' lượt'); };
      speechSynthesis.speak(u); }
  },900);
}
document.getElementById('arm').onclick=function(){
  try{ ac=new (window.AudioContext||window.webkitAudioContext)(); }catch(e){}
  if(ac&&ac.state==='suspended')ac.resume();
  if(window.speechSynthesis){ var w=new SpeechSynthesisUtterance(' '); speechSynthesis.speak(w); }
  armed=true; this.classList.add('on'); this.textContent='✓ LOA ĐÃ SẴN SÀNG';
  document.getElementById('led').className='led ok';
  document.getElementById('stx').textContent='ĐANG TRỰC — poll hệ thống mỗi 8 giây';
  log('Trạm loa đã kích hoạt, bắt đầu trực'); pickVoice(); poll();
};
document.getElementById('test').onclick=function(){
  if(!armed){alert('Bấm KÍCH HOẠT LOA trước.');return;}
  log('Phát thử'); say('Đây là bản tin thử của trạm loa bản. Hệ thống cảnh báo sớm Aether đang hoạt động bình thường.',1,''); };
document.getElementById('stop').onclick=function(){ if(window.speechSynthesis)speechSynthesis.cancel(); log('Đã dừng phát'); };

function poll(){
  fetch('./aether-loa'+(XA?('?x='+XA):''),{cache:'no-store'}).then(function(r){return r.json();}).then(function(s){
    document.getElementById('led').className='led ok';
    if(s&&s.ts&&s.ts!==lastTs){
      lastTs=s.ts;
      var cd=document.getElementById('card'); cd.className='card live'+(s.lv==='CRITICAL'?' crit':(s.lv==='WARNING'?' warn':''));
      document.getElementById('led').className='led live';
      document.getElementById('ttl').textContent=(s.kind==='ban_tin_sang'?'☀ ':(s.lv==='CRITICAL'?'🔴 ':'🟠 '))+(s.title||'Bản tin')+' — '+(s.name||'');
      document.getElementById('scr').textContent=s.loa_script||'';
      var lanPhat = (s.kind==='ban_tin_sang') ? 1 : 3;
      var nhan = (s.kind==='ban_tin_sang') ? '☀ Bản tin sáng' : '★ CẢNH BÁO '+s.lv+' / '+s.rt;
      log(nhan+' tại '+(s.name||'')+' — phát loa '+lanPhat+' lượt', s.kind!=='ban_tin_sang');
      say(s.loa_script||'',lanPhat,s.audio_url||'');
    }
  }).catch(function(){ document.getElementById('led').className='led'; log('✗ Mất kết nối tới hệ thống'); })
  .then(function(){ setTimeout(poll,8000); });
}
</script>
