function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
function parseCSV(text){
  const rows=[];let row=[],cur='',q=false;
  for(let i=0;i<text.length;i++){const c=text[i];
    if(q){if(c==='"'){if(text[i+1]==='"'){cur+='"';i++;}else q=false;}else cur+=c;}
    else if(c==='"')q=true;
    else if(c===','){row.push(cur);cur='';}
    else if(c==='\n'){row.push(cur);rows.push(row);row=[];cur='';}
    else if(c!=='\r')cur+=c;}
  if(cur!==''||row.length){row.push(cur);rows.push(row);}
  if(!rows.length)return[];
  const hdr=rows.shift().map(h=>h.trim().replace(/^\ufeff/,''));
  return rows.filter(r=>r.some(v=>String(v).trim()!==''))
    .map(r=>{const o={};hdr.forEach((h,i)=>o[h]=String(r[i]==null?'':r[i]).trim());return o;});
}
const num = v => { const n = parseFloat(String(v==null?'':v).replace(',','.')); return isFinite(n)?n:null; };

// DEMO MODE — bơm kịch bản vào ĐẦU pipeline. Consensus/RAG/Agent phía sau chạy THẬT.
// Body: { "scenario":"flood|landslide|frost|fog", "xa_id":"tua_thang" }
const b = ($json.body)||{};
const sc = b.scenario || 'flood';
let sd={}; try { sd = $getWorkflowStaticData('global'); } catch(e){}
const reg = sd.registry;
if (!reg) throw new Error('Chưa có registry — chạy pipeline chính (hoặc Execute node "Dựng điểm đo") ít nhất 1 lần trước khi simulate.');

const target = b.xa_id || reg.points[0].xa_id;
if (!reg.communes[target]) throw new Error('xa_id "' + target + '" không có trong sổ địa bàn. Các mã hợp lệ: ' + Object.keys(reg.communes).slice(0,8).join(', ') + '…');

const P = { flood:{rain:80,soil:92,tmin:22,vis:5000,q:2.7},
            landslide:{rain:60,soil:94,tmin:22,vis:5000,q:1.2},
            frost:{rain:2,soil:40,tmin:-1,vis:4000,q:0.9},
            fog:{rain:1,soil:45,tmin:12,vis:30,q:0.8} }[sc] || {rain:80,soil:92,tmin:22,vis:5000,q:2.7};

// chỉ ĐIỂM XẤU NHẤT của xã đích bị bơm -> chứng minh cơ chế quy về xã theo max hoạt động
const hitPoint = reg.points.filter(p=>p.xa_id===target)[0].point_id;
const points = reg.points.map(p => {
  const hit = p.point_id===hitPoint;
  return { ...p,
    forecast_next24: hit?P.rain:3, soilNow: hit?P.soil:45, t_min_next24: hit?P.tmin:19,
    vis_min: hit?P.vis:8000, qRatio: hit?P.q:0.9, bias_mm: 0, bias_per_day: 0, daily:null };
});
return [{ json:{ __simulated:true, scenario:sc, target_xa:target, registry:reg, points } }];

// Đăng ký nhận tin — trả lời bài toán "thu thập vị trí người dùng" mà KHÔNG cần GPS.
// Đơn vị cá nhân hóa là BẢN/XÃ (tĩnh, cán bộ bản biết rõ), không phải toạ độ.
// Body: { "so_dien_thoai":"09...", "ho_ten":"...", "xa_id":"tua_thang", "ban":"Bản Tủa Thàng",
