const b = ($json.body)||{};
const XA = ['tua_thang','muong_nhe','sin_thau'];
const errs = [];
const phone = String(b.so_dien_thoai||'').replace(/[^0-9+]/g,'');
if (!/^(0|\+84)[0-9]{9}$/.test(phone)) errs.push('so_dien_thoai không hợp lệ');
if (!XA.includes(b.xa_id)) errs.push('xa_id phải thuộc: ' + XA.join(', '));
if (!b.ban) errs.push('thiếu ban');
if (errs.length) return [{ json:{ ok:false, errors:errs } }];

const rec = { id:'REG'+Date.now().toString(36).toUpperCase(), ho_ten:b.ho_ten||'', so_dien_thoai:phone,
  xa_id:b.xa_id, ban:b.ban, vai_tro:(b.vai_tro==='can_bo_ban'?'can_bo_ban':'dan'),
  ngon_ngu:['vi','hmong','thai'].includes(b.ngon_ngu)?b.ngon_ngu:'vi',
  sinh_ke:b.sinh_ke||'khac', lat:b.lat||'', lon:b.lon||'', trang_thai:'active',
  registered_at:new Date().toISOString() };

// MVP: lưu tạm vào static data. PRODUCTION: bật node "Google Sheets — Ghi danh bạ" bên cạnh (cần OAuth).
try {
  const sd = $getWorkflowStaticData('global');
