return [{ json:{ ok:true, record:rec,
  note:'Đã ghi nhận. MVP lưu vào static data; bản triển khai ghi thẳng vào Google Sheet DanhBa.' } }];

// --- HÀM TIỆN ÍCH ---
function toE164(sdt){
  var s=String(sdt==null?'':sdt).replace(/[^0-9+]/g,'');
  if(s.indexOf('+')===0)return s;
  if(s.indexOf('84')===0&&s.length>=11)return '+'+s;
  if(s.indexOf('0')===0)return '+84'+s.slice(1);
  if(s.length===9)return '+84'+s;
  return s;
}
function stripVn(s){return String(s==null?'':s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D');}
function r0(x){return (x==null||isNaN(x))?null:Math.round(x);}
function dm(dstr){ if(!dstr)return ''; var p=String(dstr).split('-'); return p.length===3?(p[2]+'/'+p[1]):''; }

// Dịch SỐ sang LỜI để bà con hình dung được (giữ cả số lẫn lời)
function muaThanhLoi(mm){
  if(mm==null) return '';
  if(mm<1)  return 'hau nhu khong mua';
  if(mm<16) return 'mua khong lon ('+Math.round(mm)+'mm)';
  if(mm<30) return 'mua kha ('+Math.round(mm)+'mm)';
  if(mm<50) return 'MUA TO ('+Math.round(mm)+'mm)';
  return 'MUA RAT TO ('+Math.round(mm)+'mm), de gay lu';
}
function nhietThanhLoi(thap,cao){
  var t=r0(thap), c=r0(cao);
  if(t==null||c==null) return '';
  var loi='';
  if(t<8)  loi=' (ret dam, nho giu am)';
  else if(t<13) loi=' (troi lanh)';
  else if(c>34) loi=' (nong)';
  return t+'-'+c+' do'+loi;
}

const CONFIG={ BASE_URL:'https://n8n.phaco.com.vn/webhook', SMS_MAX_SEGMENTS:4 };

const groups=$('Nhóm sinh kế + soạn prompt').all().map(i=>i.json);
const replies=$input.all().map(i=>i.json);
const out=[];

for(let i=0;i<groups.length;i++){
  const g=groups[i];
  if(g.__skip)continue;

  let raw=((((replies[i]||{}).choices||[])[0]||{}).message||{}).content||'';
  const rc=((((replies[i]||{}).choices||[])[0]||{}).message||{}).reasoning_content;
  if(!raw && rc) raw=rc;
  let clean=String(raw).replace(/```json/g,'').replace(/```/g,'').trim();
  const s=clean.indexOf('{'),e=clean.lastIndexOf('}');
  if(s!==-1&&e!==-1)clean=clean.substring(s,e+1);
  let r; try{r=JSON.parse(clean);}catch(err){r={};}
  let kn=r.khuyen_nghi||'nho xem troi truoc khi di lam';
  kn=String(kn).trim().replace(/[.。]+$/,'');
  kn=kn.charAt(0).toUpperCase()+kn.slice(1);

  const w=g.weather_facts||{};
  const shortName=String(g.xa_name||'').replace(/^(Xã|Phường) /,'').replace(/\s*\(.*\)$/,'');
  const link=CONFIG.BASE_URL+'/aether-view?x='+g.xa_id;

  var troi=stripVn(w.troi||'thay doi');
  var nhiet=nhietThanhLoi(w.thap,w.cao);
  var mua=muaThanhLoi(w.mua_mm);
  // ghép mô tả thời tiết: "troi mua phun, mua nho (12mm), 24-27 do"
  var moTa=[troi, mua, nhiet].filter(Boolean).join(', ');

  // Xu hướng nói kiểu dặn dò
  var xuhuong='';
  if(w.mua_3ngay && w.mua_3ngay.length>=3){
    var a=w.mua_3ngay[0]||0, cc=w.mua_3ngay[2]||0;
    if(cc>a+5) xuhuong=' May ngay toi mua se nang hon, ba con luu y.';
    else if(cc<a-5) xuhuong=' May ngay toi mua se ngot dan.';
  }

  for(const p of g.recipients){
    // Cảnh báo (nếu có) — nói thẳng, khẩn
    var canhBao='';
    if(g.alert_level && g.alert_level!=='SAFE'){
      var loaiVN={flood:'nguy co lu quet',landslide:'nguy co sat lo',frost:'ret hai',fog:'suong mu day'}[g.risk_type]||'thoi tiet nguy hiem';
      canhBao=' CANH BAO: '+stripVn(loaiVN)+', ba con het suc chu y!';
    }

    // Tin giọng gần gũi: "Ba con [ban] o [xa] oi, hom nay [thoi tiet]. [khuyen nghi]. [canh bao] Xem: [link]"
    var text=stripVn(
      'Ba con '+shortName+' oi! '
      + 'Hom nay '+dm(w.ngay)+' '+moTa+'. '
      + kn+'.'
      + xuhuong
      + canhBao+' '
      + 'Xem chi tiet 7 ngay: '+link
    );

    out.push({ json:{
      to:toE164(p.to), ho_ten:p.ho_ten, ban:p.ban, xa_id:g.xa_id, vai_tro:p.vai_tro,
      message:text, len:text.length, segments:Math.ceil(text.length/153),
      loai:'ban_tin_sang', alert_level:g.alert_level||'SAFE'
    }});
  }
}

// ===== GHI BẢN TIN ĐỌC LOA THEO XÃ (chung 1 lần/sáng) =====
try {
  const sd=$getWorkflowStaticData('global'); sd.loaMorning=sd.loaMorning||{};
  const seen={};
  for(const g of groups){
    if(g.__skip||seen[g.xa_id])continue; seen[g.xa_id]=true;
    const w=g.weather_facts||{};
    const sn=String(g.xa_name||'').replace(/^(Xã|Phường) /,'');
    let troi=w.troi||'thay đổi';
    let nhiet=(w.thap!=null&&w.cao!=null)?('nhiệt độ từ '+Math.round(w.thap)+' đến '+Math.round(w.cao)+' độ'):'';
    let mua='';
    if(w.mua_mm!=null){ if(w.mua_mm<1)mua='hầu như không mưa'; else if(w.mua_mm<16)mua='có mưa nhỏ';
      else if(w.mua_mm<30)mua='có mưa'; else if(w.mua_mm<50)mua='có mưa to'; else mua='có mưa rất to, đề phòng lũ'; }
    const cb=(g.alert_level&&g.alert_level!=='SAFE')
      ?(' Đặc biệt chú ý, hôm nay có nguy cơ '+({flood:'lũ quét',landslide:'sạt lở đất',frost:'rét hại',fog:'sương mù dày'}[g.risk_type]||'thời tiết nguy hiểm')+', bà con hết sức cẩn thận.'):'';
    const script='Bà con '+sn+' chú ý. Bản tin thời tiết sáng nay. Hôm nay trời '+troi+', '
      +[mua,nhiet].filter(Boolean).join(', ')+'.'+cb+' Bà con nhớ xem thời tiết trước khi đi làm. Xin cảm ơn.';
    sd.loaMorning[g.xa_id]={ ts:Math.floor(Date.now()/1000), loc:g.xa_id, name:g.xa_name,
      lv:g.alert_level||'SAFE', title:'Bản tin sáng '+sn, loa_script:script, audio_url:'' };
  }
}catch(e){}

return out.length>0?out:[{ json:{ __empty:true } }];
